// SPDX-License-Identifier: ISC
//! Replay of frozen peer/address RPC handler vectors generated by an
//! in-package dump test running inside dcrd's internal/rpcserver
//! package at release-v2.1.5: 24 cases across getpeerinfo,
//! getaddednodeinfo, existsaddress, existsaddresses, and
//! ticketsforaddress, each carrying the marshalled request params
//! (parsed here through the ported dcrjson pipeline), the mock seam
//! facts, and the marshalled result or the exact error code and
//! message.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chaincfg::mainnet_params;
use dcroxide_chainhash::Hash;
use dcroxide_dcrjson::{GoType, GoValue, RPCError, Registry, gojson, parse_params};
use dcroxide_rpc::handlers;
use dcroxide_rpc::helpers::NoInterfaces;
use dcroxide_rpc::server::{
    Config, RpcAddedNode, RpcBestState, RpcChain, RpcClock, RpcConnManager, RpcExistsAddresser,
    RpcPeerInfo, RpcSubsidyParams, RpcSyncManager, Server,
};
use dcroxide_rpctypes::chainsvrresults as results;
use dcroxide_rpctypes::{method, register_all};
use dcroxide_standalone::SubsidyCache;
use dcroxide_txscript::stdaddr::Address;
use dcroxide_wire::PROTOCOL_VERSION;

const VECTORS: &str = include_str!("data/rpchandlers6_vectors.txt");

fn unhex(s: &str) -> Vec<u8> {
    (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect()
}

fn utf8(hex: &str) -> String {
    String::from_utf8(unhex(hex)).unwrap()
}

/// Split a JSON array into the raw JSON text of its elements.
fn split_json_array(data: &str) -> Vec<String> {
    let bytes = data.as_bytes();
    assert_eq!(bytes.first(), Some(&b'['), "params must be an array");
    let mut elems = Vec::new();
    let mut depth = 0i32;
    let mut in_string = false;
    let mut escaped = false;
    let mut start = None;
    for (i, &b) in bytes.iter().enumerate() {
        if in_string {
            if escaped {
                escaped = false;
            } else if b == b'\\' {
                escaped = true;
            } else if b == b'"' {
                in_string = false;
            }
            continue;
        }
        match b {
            b'"' => {
                in_string = true;
                if start.is_none() {
                    start = Some(i);
                }
            }
            b'[' | b'{' => {
                if depth > 0 && start.is_none() {
                    start = Some(i);
                }
                depth += 1;
            }
            b']' | b'}' => {
                depth -= 1;
                if depth == 0 {
                    if let Some(s) = start {
                        elems.push(data[s..i].trim().to_string());
                    }
                    break;
                }
            }
            b',' if depth == 1 => {
                if let Some(s) = start {
                    elems.push(data[s..i].trim().to_string());
                }
                start = None;
            }
            b' ' | b'\t' | b'\n' | b'\r' => {}
            _ => {
                if depth == 1 && start.is_none() {
                    start = Some(i);
                }
            }
        }
    }
    elems
}

/// The scripted connection manager.
struct MockConnMgr6 {
    peers: Vec<RpcPeerInfo>,
    persistent: Vec<RpcAddedNode>,
    lookup: Result<Vec<String>, String>,
}

impl RpcConnManager for MockConnMgr6 {
    fn connected_peers(&mut self) -> Vec<RpcPeerInfo> {
        self.peers.clone()
    }
    fn persistent_peers(&mut self) -> Vec<RpcAddedNode> {
        self.persistent.clone()
    }
    fn lookup(&mut self, _host: &str) -> Result<Vec<String>, String> {
        self.lookup.clone()
    }
}

/// The scripted exists-address index.
struct MockExistsAddresser {
    tip: Result<(i64, Hash), String>,
    signal_on_wait: bool,
    exists: Result<bool, String>,
    exists_many: Result<Vec<bool>, String>,
}

impl RpcExistsAddresser for MockExistsAddresser {
    fn name(&mut self) -> String {
        "testExistsAddresser".to_string()
    }
    fn tip(&mut self) -> Result<(i64, Hash), String> {
        self.tip.clone()
    }
    fn wait_for_sync(&mut self) -> bool {
        self.signal_on_wait
    }
    fn exists_address(&mut self, _addr: &Address) -> Result<bool, String> {
        self.exists.clone()
    }
    fn exists_addresses(&mut self, _addrs: &[Address]) -> Result<Vec<bool>, String> {
        self.exists_many.clone()
    }
}

/// The scripted sync manager and clock.
struct MockSyncMgr6(i32);

impl RpcSyncManager for MockSyncMgr6 {
    fn sync_peer_id(&mut self) -> i32 {
        self.0
    }
}

struct MockClock6(i64);

impl RpcClock for MockClock6 {
    fn since_nanos(&mut self, _t: i64) -> i64 {
        self.0
    }
}

/// The scripted chain seam.
struct MockChain6 {
    best: RpcBestState,
    tickets: Result<Vec<Hash>, String>,
}

impl RpcChain for MockChain6 {
    fn best_snapshot(&mut self) -> RpcBestState {
        self.best.clone()
    }
    fn tickets_with_address(&mut self, _addr: &Address) -> Result<Vec<Hash>, String> {
        self.tickets.clone()
    }
}

fn dispatch(
    server: &mut Server<MockChain6>,
    method_name: &str,
    cmd: &GoValue,
) -> Result<(GoValue, GoType), RPCError> {
    let (result, typ) = match method_name {
        "getpeerinfo" => (
            handlers::handle_get_peer_info(server, cmd)?,
            results::get_peer_info_result().ptr().slice(),
        ),
        "getaddednodeinfo" => {
            let value = handlers::handle_get_added_node_info(server, cmd)?;
            let typ = match &value {
                GoValue::Array(items) if items.iter().all(|v| matches!(v, GoValue::String(_))) => {
                    GoType::String.slice()
                }
                _ => results::get_added_node_info_result().ptr().slice(),
            };
            (value, typ)
        }
        "existsaddress" => (handlers::handle_exists_address(server, cmd)?, GoType::Bool),
        "existsaddresses" => (
            handlers::handle_exists_addresses(server, cmd)?,
            GoType::String,
        ),
        "ticketsforaddress" => (
            handlers::handle_tickets_for_address(server, cmd)?,
            results::tickets_for_address_result(),
        ),
        other => panic!("unknown method {other}"),
    };
    Ok((result, typ))
}

#[test]
fn peer_address_handler_slice_matches_dcrd() {
    let params = mainnet_params();
    let mut registry = Registry::new();
    register_all(&mut registry);

    // Fixtures.
    let mut peers: Vec<RpcPeerInfo> = Vec::new();
    let mut persistent: Vec<RpcAddedNode> = Vec::new();
    let mut since_nanos: i64 = 0;
    for line in VECTORS.lines() {
        let f: Vec<&str> = line.split('|').collect();
        match f[0] {
            "pinfo" => {
                peers.push(RpcPeerInfo {
                    id: f[1].parse().unwrap(),
                    addr: f[2].to_string(),
                    local_addr: (f[3] != "-").then(|| f[3].to_string()),
                    services: f[4].parse().unwrap(),
                    tx_relay_disabled: f[5] == "true",
                    last_send_unix: f[6].parse().unwrap(),
                    last_recv_unix: f[7].parse().unwrap(),
                    bytes_sent: f[8].parse().unwrap(),
                    bytes_recv: f[9].parse().unwrap(),
                    conn_time_unix: f[10].parse().unwrap(),
                    time_offset: f[11].parse().unwrap(),
                    version: f[12].parse().unwrap(),
                    user_agent: f[13].to_string(),
                    inbound: f[14] == "true",
                    starting_height: f[15].parse().unwrap(),
                    last_block: f[16].parse().unwrap(),
                    ban_score: f[17].parse().unwrap(),
                    last_ping_nonce: f[18].parse().unwrap(),
                    last_ping_time_unix_nanos: f[19].parse().unwrap(),
                    last_ping_micros: f[20].parse().unwrap(),
                    connected: f[21] == "true",
                });
            }
            "ppeer" => {
                persistent.push(RpcAddedNode {
                    addr: f[1].to_string(),
                    connected: f[2] == "true",
                    inbound: f[3] == "true",
                });
            }
            "since" => since_nanos = f[1].parse().unwrap(),
            _ => {}
        }
    }
    assert_eq!(peers.len(), 2, "peer fixtures");
    assert_eq!(persistent.len(), 2, "persistent peer fixtures");

    let lines: Vec<&str> = VECTORS
        .lines()
        .filter(|l| l.starts_with("case|") || l.starts_with("mock6|") || l.starts_with("result|"))
        .collect();
    let mut cases = 0;
    let mut i = 0;
    while i < lines.len() {
        let case: Vec<&str> = lines[i].split('|').collect();
        let mock: Vec<&str> = lines[i + 1].split('|').collect();
        let result: Vec<&str> = lines[i + 2].split('|').collect();
        assert_eq!(case[0], "case");
        assert_eq!(mock[0], "mock6");
        assert_eq!(result[0], "result");
        i += 3;
        cases += 1;

        let name = case[2];
        let method_name = case[3];
        let params_json = utf8(case[4]);

        // Parse the command through the ported pipeline.
        let raw_params = split_json_array(&params_json);
        let param_refs: Vec<&str> = raw_params.iter().map(|s| s.as_str()).collect();
        let cmd_instance = parse_params(&registry, &method(method_name), &param_refs)
            .unwrap_or_else(|e| panic!("{name}: parse params: {e:?}"));
        let cmd = GoValue::Struct(cmd_instance.fields);

        // The exists-addresser part of the row is either the single
        // "NONE" field or seven inline fields.
        let (exists_addresser, rest): (Option<Box<dyn RpcExistsAddresser>>, &[&str]) =
            if mock[4] == "NONE" {
                (None, &mock[5..])
            } else {
                let tip = match mock[4].strip_prefix("ERR:") {
                    Some(err) => Err(err.to_string()),
                    None => Ok((mock[5].parse().unwrap(), mock[6].parse().unwrap())),
                };
                let exists = match mock[8].strip_prefix("ERR:") {
                    Some(err) => Err(err.to_string()),
                    None => Ok(mock[8] == "true"),
                };
                let exists_many = match mock[9].strip_prefix("ERR:") {
                    Some(err) => Err(err.to_string()),
                    None => Ok(mock[9]
                        .split(',')
                        .filter(|b| !b.is_empty())
                        .map(|b| b == "true")
                        .collect()),
                };
                (
                    Some(Box::new(MockExistsAddresser {
                        tip,
                        signal_on_wait: mock[7] == "true",
                        exists,
                        exists_many,
                    })),
                    &mock[11..],
                )
            };
        // rest: [tickets, bestheight, besthash, haspeers]
        let tickets = match rest[0].strip_prefix("ERR:") {
            Some(err) => Err(err.to_string()),
            None => Ok(rest[0]
                .split(',')
                .filter(|h| !h.is_empty())
                .map(|h| h.parse().unwrap())
                .collect()),
        };
        let chain = MockChain6 {
            best: RpcBestState {
                hash: rest[2].parse().unwrap(),
                prev_hash: Hash([0u8; 32]),
                height: rest[1].parse().unwrap(),
                bits: 0,
                next_stake_diff: 0,
                total_subsidy: 0,
            },
            tickets,
        };
        let conn_mgr = MockConnMgr6 {
            peers: if rest[3] == "true" {
                peers.clone()
            } else {
                Vec::new()
            },
            persistent: persistent.clone(),
            lookup: match mock[3].strip_prefix("ERR:") {
                Some(err) => Err(err.to_string()),
                // The addresses the dump's lookup mock resolves.
                None => Ok(vec!["192.0.2.11".to_string(), "2001:db8::11".to_string()]),
            },
        };
        let mut server = Server::new(Config {
            chain,
            chain_params: params.clone(),
            subsidy_cache: SubsidyCache::new(RpcSubsidyParams(params.clone())),
            min_relay_tx_fee: 10000,
            max_protocol_version: PROTOCOL_VERSION,
            sync_mgr: Box::new(MockSyncMgr6(mock[2].parse().unwrap())),
            conn_mgr: Box::new(conn_mgr),
            tx_mempooler: Box::new(()),
            clock: Box::new(MockClock6(since_nanos)),
            interfaces: Box::new(NoInterfaces),
            rand_u64: Box::new(|| 0),
            tx_indexer: None,
            db: Box::new(()),
            filterer_v2: Box::new(()),
            exists_addresser,
        });

        match dispatch(&mut server, method_name, &cmd) {
            Ok((value, typ)) => {
                assert_eq!(result[2], "ok", "{name}: expected an error");
                let got = gojson::encode(&typ, &value);
                assert_eq!(got, utf8(result[3]), "{name}: result");
            }
            Err(err) => {
                assert_eq!(result[2], "err", "{name}: unexpected error {err:?}");
                assert_eq!(
                    i64::from(err.code),
                    result[3].parse::<i64>().unwrap(),
                    "{name}: error code ({})",
                    err.message
                );
                assert_eq!(err.message, utf8(result[4]), "{name}: error message");
            }
        }
    }
    assert_eq!(cases, 24, "unexpected case count");
}
